            i18nKey={"transTest.key1" as unknown as TranslationKeys}
            audience="world"
          />
        </div>
        <div data-testid="test2">
          <Trans
            i18nKey={"transTest.key2" as unknown as TranslationKeys}
            link={(el) => <a href="https://example.com">{el}</a>}
