+import { cleanup, render, screen } from "@testing-library/react";
+import { THEME } from "@excalidraw/common";
+import { UIAppStateContext } from "@excalidraw/excalidraw/context/ui-appState";
+import { EditorJotaiProvider } from "@excalidraw/excalidraw/editor-jotai";
+import { afterEach, describe, expect, it, vi } from "vitest";
+
+import { Provider, appJotaiStore } from "../app-jotai";
+import { activeRoomLinkAtom } from "../collab/Collab";
+import { ShareDialog, shareDialogStateAtom } from "../share/ShareDialog";
+
+vi.mock("../share/QRCode", () => ({
+  QRCode: () => <div data-testid="share-qr-code" />,
+}));
+
+const ACTIVE_ROOM_LINK = "https://excalidraw.com/#room=test-room,test-key";
+
+const originalNavigatorShare = window.navigator.share;
+const hadOwnNavigatorShare = Object.prototype.hasOwnProperty.call(
+  window.navigator,
+  "share",
+);
+
+const collabAPI = {
+  getUsername: () => "Alice",
+  isCollaborating: () => true,
+  setCollabError: vi.fn(),
+  setUsername: vi.fn(),
+  startCollaboration: vi.fn(),
+  stopCollaboration: vi.fn(),
+  syncElements: vi.fn(),
+  fetchImageFilesFromFirebase: vi.fn(),
+  getActiveRoomLink: () => ACTIVE_ROOM_LINK,
+  onPointerUpdate: vi.fn(),
+} as any;
+
+const renderShareDialog = () => {
+  appJotaiStore.set(shareDialogStateAtom, { isOpen: true, type: "share" });
+  appJotaiStore.set(activeRoomLinkAtom, ACTIVE_ROOM_LINK);
+
+  return render(
+    <EditorJotaiProvider>
+      <Provider store={appJotaiStore}>
+        <UIAppStateContext.Provider
+          value={{ openDialog: null, theme: THEME.LIGHT } as any}
+        >
+          <ShareDialog collabAPI={collabAPI} onExportToBackend={vi.fn()} />
+        </UIAppStateContext.Provider>
+      </Provider>
+    </EditorJotaiProvider>,
+  );
+};
+
+describe("ShareDialog", () => {
+  afterEach(() => {
+    cleanup();
+    appJotaiStore.set(shareDialogStateAtom, { isOpen: false });
+    appJotaiStore.set(activeRoomLinkAtom, null);
+
+    if (hadOwnNavigatorShare) {
+      Object.defineProperty(window.navigator, "share", {
+        configurable: true,
+        value: originalNavigatorShare,
+      });
+    } else {
+      Reflect.deleteProperty(window.navigator, "share");
+    }
+  });
+
+  it("shows a share hint when Web Share is unsupported", () => {
+    Reflect.deleteProperty(window.navigator, "share");
+
+    renderShareDialog();
+
+    expect(
+      screen.getByText("Share this link with anyone you want to collaborate with:"),
+    ).toBeInTheDocument();
+  });
+
+  it("hides the fallback share hint when Web Share is supported", () => {
+    Object.defineProperty(window.navigator, "share", {
+      configurable: true,
+      value: vi.fn(),
+    });
+
+    renderShareDialog();
+
+    expect(
+      screen.queryByText(
+        "Share this link with anyone you want to collaborate with:",
+      ),
+    ).not.toBeInTheDocument();
+  });
+});
"}}

